import sailpoint.object.ProvisioningPlan;
      import sailpoint.object.ProvisioningPlan.AccountRequest;
      import sailpoint.object.ProvisioningPlan.AttributeRequest;
      import sailpoint.object.ProvisioningPlan.Operation;
      import sailpoint.object.Application;

      Application application = context.getObjectByName(Application.class, "ActiveDirectory");
      log.error("application : "+application);

       if (accountRequest != null @and accountRequest != void @and field != null @and field != void ) {    
        log.error("AccountRequest Operation :" + accountRequest.getOperation());
        log.error("AttributeRequest Operation :" + accountRequest.getAttributeRequest("memberOf").getOperation());
        if (accountRequest.getOperation().equals(AccountRequest.Operation.Create) @and accountRequest.getAttributeRequest("memberOf").getOperation().equals(ProvisioningPlan.Operation.Add) ) {
          String entValue = accountRequest.getAttributeRequest("memberOf").getValue();
          log.error("entValue : "+entValue);
          if (entValue != null @and entValue.equalsIgnoreCase("CN=BenefitCommittee,OU=Groups,OU=Demo,DC=Eshiam,DC=com")) {
            log.error("Entered into the entValue");
            field.setRequired(true);
            field.setReviewRequired(false);
            return "NewValue";
          }else{return null;}
        } else {
          log.error("Entered into the else condition ");
          field.setRequired(false);
          return null;
        }
      }
      log.error("END FieldValue - SelectBusinessUnit - iSPARC 5629");
